// Twisty Fidget Egg — bold spiraling petal-slices carved into an egg silhouette.
//
// Technique: a fluted petal CrossSection (a polar curve whose radius swings
// between a deep valley and a high crest `petals` times around) is extruded
// tall with a big twist + high nDiv, then INTERSECTED with a revolved egg
// solid. The deep flutes of the twisted column slice clean spiral channels and
// pronounced ridges that wrap the WHOLE egg, top pole to bottom pole — the
// classic "twisty ball" feel on an egg you keep turning over in your palm.
const { Manifold, CrossSection } = api;

const p = api.params({
  eggRadius: { type: 'number', default: 16, min: 8,  max: 30, step: 0.5, unit: 'mm', label: 'Egg radius (widest)' },
  elongation:{ type: 'number', default: 1.45, min: 1.1, max: 2.0, step: 0.05, label: 'Egg elongation (height / width)' },
  petals:    { type: 'int',    default: 6,  min: 4,  max: 10, label: 'Petal count' },
  twistDeg:  { type: 'number', default: 540, min: 180, max: 900, step: 15, unit: '°', label: 'Spiral twist' },
});

const R = p.eggRadius;            // widest radius of the egg (XY)
const H = R * 2 * p.elongation;   // overall egg height (Z)

// --- Egg silhouette (revolve profile) --------------------------------------
// Half-outline in the +X / +Y plane: X = radius, Y = height (Y becomes Z after
// revolve). Asymmetric oval — rounder/wider low, tapering narrower up top — via
// an egg curve where the radius at a given height is modulated by how high we
// are: bottom bulges, top pinches. Sample many points for a smooth surface.
const PROFILE_STEPS = 96;
const asym = 0.32;                // how much the top narrows vs the bottom
const profilePts = [[0, 0]];      // bottom pole on the axis
for (let i = 1; i < PROFILE_STEPS; i++) {
  const t = i / PROFILE_STEPS;    // 0 = bottom, 1 = top
  const y = t * H;
  // Base half-ellipse radius across the height.
  const ellipse = Math.sin(t * Math.PI) ** 0.5; // fuller mid/low, smooth poles
  // Egg asymmetry: shrink the upper half so the top is the narrow end.
  const taper = 1 - asym * (t - 0.5) * 2 * (t > 0.5 ? 1 : 0.35);
  const x = R * ellipse * taper;
  profilePts.push([Math.max(x, 0.001), y]);
}
profilePts.push([0, H]);          // top pole on the axis

// ofPolygons wants CCW for the outer contour; this profile walks up the +X
// silhouette (bottom→top) then back down the axis, which is CCW in X/Y.
const eggProfile = CrossSection.ofPolygons([profilePts]);
const egg = Manifold.revolve(eggProfile);   // 360° by default; inherits segment preset

// --- Fluted petal twist column ---------------------------------------------
// Instead of grazing the egg rim with shallow circular notches, the column's
// cross-section IS the petal shape: a closed polar curve sampled finely, whose
// radius oscillates `petals` times between a deep valley (`valleyR`) and a tall
// crest (`crestR`). The crests reach OUTSIDE the egg (so the ridges read as the
// egg's full surface after intersection) while the valleys plunge well INSIDE
// the egg's widest radius, so every spiral channel is a deep, bold groove —
// roughly `(crestR - valleyR)` wide — not a faint scratch on the flank.
const crestR  = R + 2.5;          // ridge crest — sits just outside the egg surface
const grooveDepth = R * 0.55;     // how deep the channels cut below the crest
const valleyR = crestR - grooveDepth;
const FLUTE_STEPS = 360;          // dense sampling so the petal curve is smooth

const petalPts = [];
for (let i = 0; i < FLUTE_STEPS; i++) {
  const a = (i / FLUTE_STEPS) * Math.PI * 2;
  // Smooth crest↔valley swing. Raising cos to an odd-ish power flattens the
  // crests into broad ridges and sharpens the valleys into clean channels —
  // bold petal-slices rather than a wavy circle.
  const wave = (Math.cos(a * p.petals) + 1) / 2;     // 0 at valley, 1 at crest
  const shaped = Math.pow(wave, 0.65);               // broaden crests a touch
  const rad = valleyR + (crestR - valleyR) * shaped;
  petalPts.push([Math.cos(a) * rad, Math.sin(a) * rad]);
}
const petalCS = CrossSection.ofPolygons([petalPts]);

// Extrude taller than the egg (so caps clear it), centered on Z, with the big
// twist. High nDiv keeps the spiral smooth — a low slice count looks faceted.
const colH = H + 8;
const nDiv = 160;
const column = petalCS
  .extrude(colH, nDiv, p.twistDeg, undefined, true) // centered on Z
  .translate([0, 0, H / 2]);                        // recenter onto the egg (egg spans 0..H)

// --- Carve the grooves into the egg ----------------------------------------
// Intersection: the egg keeps only the material inside the twisted fluted
// column. Where a crest covers the egg the surface survives (ridge); where a
// valley dips inside, that material is removed (deep spiral channel). The
// overall silhouette stays a clean egg, now wrapped in bold petal-slices.
const carved = egg.intersect(column);

// One soft pastel part — mint filament.
return api.label(carved, 'egg', { color: '#7fe0c4' });

